import ClickSpark from "@/registry/magicui/click-spark";
import { Button } from "@/components/ui/button";

export default function ClickSparkDemo() {
  return (
    <div className="relative flex h-[350px] w-full flex-col items-center justify-center overflow-hidden rounded-lg border bg-background md:shadow-xl">
      <ClickSpark
        sparkColor="#fff"
        sparkSize={10}
        sparkRadius={15}
        sparkCount={8}
